public class BSTSearch {

    static class Node {
        int val; Node left, right;
        Node(int v) { val = v; }
    }

    Node insert(Node root, int val) {
        if (root == null) return new Node(val);
        if (val < root.val) root.left  = insert(root.left,  val);
        else if (val > root.val) root.right = insert(root.right, val);
        return root;
    }

    public int search(Node root, int target) {
        // TODO: return target if root.val==target;
        //       recurse left if target < root.val, else recurse right
        //       return -1 if root is null
        if (root == null) return -1;
        return -1; // replace
    }

    int[] count = {0};
    public int kthSmallest(Node root, int k) {
        // TODO: in-order DFS; increment count each visit;
        //       when count == k, return root.val
        if (root == null) return -1;
        int left = kthSmallest(root.left, k);
        if (left != -1) return left;
        count[0]++;
        if (count[0] == k) return root.val;
        return kthSmallest(root.right, k);
    }

    public static void main(String[] args) {
        BSTSearch bst = new BSTSearch();
        Node root = null;
        for (int v : new int[]{5, 3, 7, 1, 4, 6, 8}) root = bst.insert(root, v);

        System.out.println("Search 4: " + bst.search(root, 4));
        System.out.println("Search 9: " + bst.search(root, 9));

        bst.count[0] = 0;
        System.out.println("1st smallest: " + bst.kthSmallest(root, 1));
        bst.count[0] = 0;
        System.out.println("3rd smallest: " + bst.kthSmallest(root, 3));
        bst.count[0] = 0;
        System.out.println("7th smallest: " + bst.kthSmallest(root, 7));
    }
}

